  ('social-worker-moex-06470', 'social-worker', 'social-worker-moex-103-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社工員對於案主問題有其特別的評估角度，有三個議題是所有問題都需要評估的。下列那一個不是三個 議題之一？', '["案主最初關心的問題是甚麼", "是否有法律議題是社工員與案主必須要注意的", "是否有隱私性的問題必須要注意的", "是否有潛在或危險因素會影響案主的健康與安全"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "a3d845e75c7c", "answer_pdf_sha1": "ca9f253103ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0601", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
